def tfidf_score(document: str, corpus: List[str]) -> Dict[str, float]:
    tokens = tokenize(document)
    if not tokens:
        return {}
    tf = Counter(tokens)
    total = len(tokens)
    idf = idf_scores(corpus)
    return {token: (count / total) * idf.get(token, 1.0) for token, count in tf.items()}

