@dataclass(frozen=True)
class Point:
    x: float
    y: float
    label: Optional[str] = None

    def distance_to(self, other: 'Point') -> float:
        return math.sqrt((self.x - other.x) ** 2 + (self.y - other.y) ** 2)

    def __lt__(self, other: 'Point') -> bool:
        return (self.x, self.y) < (other.x, other.y)


def manhattan_distance(p1: Point, p2: Point) -> float:
    return abs(p1.x - p2.x) + abs(p1.y - p2.y)


def find_centroid(points: List[Point]) -> Point:
    if not points:
        raise ValueError('Cannot compute centroid of empty list')
    n = len(points)
    return Point(sum(p.x for p in points) / n, sum(p.y for p in points) / n)


def bounding_box(points: List[Point]) -> Tuple[Point, Point]:
    """Return (min_corner, max_corner) of the axis-aligned bounding box."""
    min_x = min(p.x for p in points)
    min_y = min(p.y for p in points)
    max_x = max(p.x for p in points)
    max_y = max(p.y for p in points)
    return Point(min_x, min_y), Point(max_x, max_y)


def points_within_radius(center: Point, points: List[Point], radius: float) -> List[Point]:
    return [p for p in points if center.distance_to(p) <= radius]


def grid_points(x_range: Tuple[float, float], y_range: Tuple[float, float], step: float) -> Iterator[Point]:
    x = x_range[0]
    while x <= x_range[1] + 1e-9:
        y = y_range[0]
        while y <= y_range[1] + 1e-9:
