async def sleep_with_jitter(base_seconds: float, jitter_fraction: float = 0.1) -> None:
    import random
    jitter = random.uniform(0, base_seconds * jitter_fraction)
    await asyncio.sleep(base_seconds + jitter)


def is_retryable(exc: Exception, retryable_types: tuple) -> bool:
    return isinstance(exc, retryable_types)


async def run_with_timeout(coro: Awaitable[T], timeout: float) -> T:
    return await asyncio.wait_for(coro, timeout=timeout)


class CircuitBreaker:
    """Simple circuit breaker: opens after max_failures consecutive failures."""

    def __init__(self, max_failures: int = 5, reset_timeout: float = 60.0):
        self.max_failures = max_failures
        self.reset_timeout = reset_timeout
        self._failures = 0
        self._opened_at: Optional[float] = None

    @property
    def is_open(self) -> bool:
        if self._opened_at is None:
            return False
        if time.monotonic() - self._opened_at >= self.reset_timeout:
            self._failures = 0
            self._opened_at = None
            return False
        return True

    def record_failure(self) -> None:
        self._failures += 1
        if self._failures >= self.max_failures:
            self._opened_at = time.monotonic()

    def record_success(self) -> None:
        self._failures = 0
        self._opened_at = None

