        self.is_end: bool = False
        self.value: Any = None


class Trie:
    """Prefix tree supporting insert, search, starts_with, and prefix iteration."""

    def __init__(self) -> None:
        self._root = TrieNode()
        self._size = 0

    def insert(self, key: str, value: Any = True) -> None:
        node = self._root
        for ch in key:
            node = node.children.setdefault(ch, TrieNode())
        if not node.is_end:
            self._size += 1
        node.is_end = True
        node.value = value

    def search(self, key: str) -> Optional[Any]:
        node = self._root
        for ch in key:
            if ch not in node.children:
                return None
        return node.value if node.is_end else None

    def starts_with(self, prefix: str) -> bool:
        node = self._root
        for ch in prefix:
            if ch not in node.children:
                return False
        return True

    def _collect(self, node: TrieNode, prefix: str) -> Iterator[Tuple[str, Any]]:
        if node.is_end:
            yield prefix, node.value
        for ch, child in sorted(node.children.items()):
            yield from self._collect(child, prefix + ch)

    def __len__(self) -> int:
        return self._size

    def __iter__(self) -> Iterator[str]:
        for key, _ in self._collect(self._root, ''):
            yield key

