class DirectedGraph:
    """Directed graph with adjacency list representation."""

    def __init__(self) -> None:
        self._nodes: Dict[str, GraphNode] = {}
        self._edges: Dict[str, List[str]] = defaultdict(list)
        self._reverse_edges: Dict[str, List[str]] = defaultdict(list)

    def add_node(self, node_id: str, data: Any = None) -> None:
        if node_id not in self._nodes:
            self._nodes[node_id] = GraphNode(id=node_id, data=data)

    def add_edge(self, from_id: str, to_id: str) -> None:
        self.add_node(from_id)
        self.add_node(to_id)
        self._edges[from_id].append(to_id)
        self._reverse_edges[to_id].append(from_id)

    def get_node(self, node_id: str) -> Optional[GraphNode]:
        return self._nodes.get(node_id)

    def neighbors(self, node_id: str) -> List[str]:
        return self._edges.get(node_id, [])

    def in_degree(self, node_id: str) -> int:
        return len(self._reverse_edges.get(node_id, []))

    def nodes(self) -> List[str]:
        return list(self._nodes.keys())

    def bfs(self, start_id: str) -> List[str]:
        visited: List[str] = []
        seen = set()
        queue = deque([start_id])
        seen.add(start_id)
        while queue:
            node_id = queue.popleft()
            visited.append(node_id)
            for neighbor in self._edges.get(node_id, []):
                if neighbor not in seen:
                    seen.add(neighbor)
                    queue.append(neighbor)
        return visited

