                col = pos - line_start + 1
                if name == 'NEWLINE':
                    line += 1
                    line_start = pos + 1
                elif name == 'SKIP':
                    pass
                elif name == 'MISMATCH':
                    raise LexError(line, col, value)
                else:
                    tok_type = classify_ident(value) if name == 'IDENT' else name
                    tokens.append(Token(tok_type, value, line, col))
                pos = m.end()
                break
    return tokens

